<?php/** * Hooks * * All hooks that are run in the theme are listed here * * @package optix */namespace Optix;/** * Enable search view */// add_filter( 'air_helper_disable_views_search', '__return_false' );/** * Breadcrumb */// require get_theme_file_path( 'inc/hooks/breadcrumb.php' );/** * General hooks */require get_theme_file_path( 'inc/hooks/general.php' );add_action( 'widgets_init', __NAMESPACE__ . '\widgets_init' );/** * Scripts and styles associated hooks */require get_theme_file_path( 'inc/hooks/scripts-styles.php' );add_action( 'wp_enqueue_scripts', __NAMESPACE__ . '\enqueue_theme_scripts' );// NB! If you use ajax functionality in Gravity Forms, remove this line// to prevent Uncaught ReferenceError: jQuery is not definedadd_action( 'wp_default_scripts', __NAMESPACE__ . '\move_jquery_into_footer' );/** * Block styles */require get_theme_file_path( 'inc/hooks/block-styles.php' );add_action( 'init', __NAMESPACE__ . '\register_custom_block_styles' );/** * Gutenberg associated hooks */require get_theme_file_path( 'inc/hooks/gutenberg.php' );add_filter( 'allowed_block_types_all', __NAMESPACE__ . '\allowed_block_types', 10, 2 );add_filter( 'use_block_editor_for_post_type', __NAMESPACE__ . '\use_block_editor_for_post_type', 10, 2 );add_action( 'enqueue_block_editor_assets', __NAMESPACE__ . '\register_block_editor_assets' );add_action( 'after_setup_theme', __NAMESPACE__ . '\setup_editor_styles' );add_action( 'enqueue_block_editor_assets', __NAMESPACE__ . '\block_editor_title_input_styles' );/** * ACF blocks */require get_theme_file_path( 'inc/hooks/acf-blocks.php' );add_filter( 'block_categories_all', __NAMESPACE__ . '\acf_blocks_add_category_in_gutenberg', 10, 2 );add_action( 'acf/init', __NAMESPACE__ . '\acf_blocks_init' );add_filter( 'acf/fields/wysiwyg/toolbars', __NAMESPACE__ . '\add_custom_tinymce_toolbars' );/** * Form related hooks */require get_theme_file_path( 'inc/hooks/forms.php' );add_action( 'gform_enqueue_scripts', __NAMESPACE__ . '\dequeue_gf_stylesheets', 999 );/** * Template functions & option helpers */require get_theme_file_path( 'inc/template-functions.php' );/** * Theme Options (ACF) */// Always load theme options (works with or without ACF)if ( true || class_exists( 'ACF' ) ) {  require get_theme_file_path( 'inc/class-optix-theme-options.php' );  new \Optix\Theme_Options();}/** * WooCommerce */require get_theme_file_path( 'inc/hooks/woocommerce.php' );/** * Theme Customizer (ACF bridge) */require get_theme_file_path( 'inc/hooks/customizer.php' );/** * Dynamic CSS/JS */require get_theme_file_path( 'inc/dynamic-css.php' );/** * AJAX handlers */require get_theme_file_path( 'inc/ajax-handlers.php' );